import{_ as s,c as n,o as a,a5 as p}from"./chunks/framework.DwbewbAn.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"doc/数据库/Mysql/面试总结/MySQL常见SQL错误用法.md","filePath":"packages/doc/src/数据库/Mysql/面试总结/MySQL常见SQL错误用法.md","lastUpdated":1711637456000}'),e={name:"doc/数据库/Mysql/面试总结/MySQL常见SQL错误用法.md"},l=p(`<h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>MySQL在2016年仍然保持强劲的数据库流行度增长趋势。越来越多的客户将自己的应用建立在MySQL数据库之上，甚至是从Oracle迁移到MySQL上来。但也存在部分客户在使用MySQL数据库的过程中遇到一些比如响应时间慢，CPU打满等情况。阿里云RDS专家服务团队帮助云上客户解决过很多紧急问题。现将《ApsaraDB专家诊断报告》中出现的部分常见SQL问题总结如下，供大家参考。</p><h2 id="常见sql错误用法" tabindex="-1">常见SQL错误用法 <a class="header-anchor" href="#常见sql错误用法" aria-label="Permalink to &quot;常见SQL错误用法&quot;">​</a></h2><h3 id="_1-limit-语句" tabindex="-1">1. LIMIT 语句 <a class="header-anchor" href="#_1-limit-语句" aria-label="Permalink to &quot;1. LIMIT 语句&quot;">​</a></h3><p>分页查询是最常用的场景之一，但也通常也是最容易出问题的地方。比如对于下面简单的语句，一般DBA想到的办法是在type, name, create_time字段上加组合索引。这样条件排序都能有效的利用到索引，性能迅速提升。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>SELECT * </span></span>
<span class="line"><span>FROM   operation </span></span>
<span class="line"><span>WHERE  type = &#39;SQLStats&#39; </span></span>
<span class="line"><span>       AND name = &#39;SlowLog&#39; </span></span>
<span class="line"><span>ORDER  BY create_time </span></span>
<span class="line"><span>LIMIT  1000, 10;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>好吧，可能90%以上的DBA解决该问题就到此为止。但当 LIMIT 子句变成 “LIMIT 1000000,10” 时，程序员仍然会抱怨：我只取10条记录为什么还是慢？</p><p>要知道数据库也并不知道第1000000条记录从什么地方开始，即使有索引也需要从头计算一次。出现这种性能问题，多数情形下是程序员偷懒了。在前端数据浏览翻页，或者大数据分批导出等场景下，是可以将上一页的最大值当成参数作为查询条件的。SQL重新设计如下：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>SELECT   * </span></span>
<span class="line"><span>FROM     operation </span></span>
<span class="line"><span>WHERE    type = &#39;SQLStats&#39; </span></span>
<span class="line"><span>AND      name = &#39;SlowLog&#39; </span></span>
<span class="line"><span>AND      create_time &gt; &#39;2017-03-16 14:00:00&#39; </span></span>
<span class="line"><span>ORDER BY create_time limit 10;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>在新设计下查询时间基本固定，不会随着数据量的增长而发生变化。</p><h3 id="_2-隐式转换" tabindex="-1">2. 隐式转换 <a class="header-anchor" href="#_2-隐式转换" aria-label="Permalink to &quot;2. 隐式转换&quot;">​</a></h3><p>SQL语句中查询变量和字段定义类型不匹配是另一个常见的错误。比如下面的语句：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; explain extended SELECT * </span></span>
<span class="line"><span>     &gt; FROM   my_balance b </span></span>
<span class="line"><span>     &gt; WHERE  b.bpn = 14000000123 </span></span>
<span class="line"><span>     &gt;       AND b.isverified IS NULL ;</span></span>
<span class="line"><span>mysql&gt; show warnings;</span></span>
<span class="line"><span>| Warning | 1739 | Cannot use ref access on index &#39;bpn&#39; due to type or collation conversion on field &#39;bpn&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>其中字段bpn的定义为varchar(20)，MySQL的策略是将字符串转换为数字之后再比较。函数作用于表字段，索引失效。</p><p>上述情况可能是应用程序框架自动填入的参数，而不是程序员的原意。现在应用框架很多很繁杂，使用方便的同时也小心它可能给自己挖坑。</p><h3 id="_3-关联更新、删除" tabindex="-1">3. 关联更新、删除 <a class="header-anchor" href="#_3-关联更新、删除" aria-label="Permalink to &quot;3. 关联更新、删除&quot;">​</a></h3><p>虽然MySQL5.6引入了物化特性，但需要特别注意它目前仅仅针对查询语句的优化。对于更新或删除需要手工重写成JOIN。</p><p>比如下面UPDATE语句，MySQL实际执行的是循环/嵌套子查询（DEPENDENT SUBQUERY)，其执行时间可想而知。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>UPDATE operation o </span></span>
<span class="line"><span>SET    status = &#39;applying&#39; </span></span>
<span class="line"><span>WHERE  o.id IN (SELECT id </span></span>
<span class="line"><span>                FROM   (SELECT o.id, </span></span>
<span class="line"><span>                               o.status </span></span>
<span class="line"><span>                        FROM   operation o </span></span>
<span class="line"><span>                        WHERE  o.group = 123 </span></span>
<span class="line"><span>                               AND o.status NOT IN ( &#39;done&#39; ) </span></span>
<span class="line"><span>                        ORDER  BY o.parent, </span></span>
<span class="line"><span>                                  o.id </span></span>
<span class="line"><span>                        LIMIT  1) t);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>执行计划：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>+----+--------------------+-------+-------+---------------+---------+---------+-------+------+-----------------------------------------------------+</span></span>
<span class="line"><span>| id | select_type        | table | type  | possible_keys | key     | key_len | ref   | rows | Extra                                               |</span></span>
<span class="line"><span>+----+--------------------+-------+-------+---------------+---------+---------+-------+------+-----------------------------------------------------+</span></span>
<span class="line"><span>| 1  | PRIMARY            | o     | index |               | PRIMARY | 8       |       | 24   | Using where; Using temporary                        |</span></span>
<span class="line"><span>| 2  | DEPENDENT SUBQUERY |       |       |               |         |         |       |      | Impossible WHERE noticed after reading const tables |</span></span>
<span class="line"><span>| 3  | DERIVED            | o     | ref   | idx_2,idx_5   | idx_5   | 8       | const | 1    | Using where; Using filesort                         |</span></span>
<span class="line"><span>+----+--------------------+-------+-------+---------------+---------+---------+-------+------+-----------------------------------------------------+</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>重写为JOIN之后，子查询的选择模式从DEPENDENT SUBQUERY变成DERIVED,执行速度大大加快，从7秒降低到2毫秒。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>UPDATE operation o </span></span>
<span class="line"><span>       JOIN  (SELECT o.id, </span></span>
<span class="line"><span>                            o.status </span></span>
<span class="line"><span>                     FROM   operation o </span></span>
<span class="line"><span>                     WHERE  o.group = 123 </span></span>
<span class="line"><span>                            AND o.status NOT IN ( &#39;done&#39; ) </span></span>
<span class="line"><span>                     ORDER  BY o.parent, </span></span>
<span class="line"><span>                               o.id </span></span>
<span class="line"><span>                     LIMIT  1) t</span></span>
<span class="line"><span>         ON o.id = t.id </span></span>
<span class="line"><span>SET    status = &#39;applying&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>执行计划简化为：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>+----+-------------+-------+------+---------------+-------+---------+-------+------+-----------------------------------------------------+</span></span>
<span class="line"><span>| id | select_type | table | type | possible_keys | key   | key_len | ref   | rows | Extra                                               |</span></span>
<span class="line"><span>+----+-------------+-------+------+---------------+-------+---------+-------+------+-----------------------------------------------------+</span></span>
<span class="line"><span>| 1  | PRIMARY     |       |      |               |       |         |       |      | Impossible WHERE noticed after reading const tables |</span></span>
<span class="line"><span>| 2  | DERIVED     | o     | ref  | idx_2,idx_5   | idx_5 | 8       | const | 1    | Using where; Using filesort                         |</span></span>
<span class="line"><span>+----+-------------+-------+------+---------------+-------+---------+-------+------+-----------------------------------------------------+</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="_4-混合排序" tabindex="-1">4. 混合排序 <a class="header-anchor" href="#_4-混合排序" aria-label="Permalink to &quot;4. 混合排序&quot;">​</a></h3><p>MySQL不能利用索引进行混合排序。但在某些场景，还是有机会使用特殊方法提升性能的。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>SELECT * </span></span>
<span class="line"><span>FROM   my_order o </span></span>
<span class="line"><span>       INNER JOIN my_appraise a ON a.orderid = o.id </span></span>
<span class="line"><span>ORDER  BY a.is_reply ASC, </span></span>
<span class="line"><span>          a.appraise_time DESC </span></span>
<span class="line"><span>LIMIT  0, 20</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>执行计划显示为全表扫描：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>+----+-------------+-------+--------+-------------+---------+---------+---------------+---------+-+</span></span>
<span class="line"><span>| id | select_type | table | type   | possible_keys     | key     | key_len | ref      | rows    | Extra    </span></span>
<span class="line"><span>+----+-------------+-------+--------+-------------+---------+---------+---------------+---------+-+</span></span>
<span class="line"><span>|  1 | SIMPLE      | a     | ALL    | idx_orderid | NULL    | NULL    | NULL    | 1967647 | Using filesort |</span></span>
<span class="line"><span>|  1 | SIMPLE      | o     | eq_ref | PRIMARY     | PRIMARY | 122     | a.orderid |       1 | NULL           |</span></span>
<span class="line"><span>+----+-------------+-------+--------+---------+---------+---------+-----------------+---------+-+</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>由于is_reply只有0和1两种状态，我们按照下面的方法重写后，执行时间从1.58秒降低到2毫秒。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>SELECT * </span></span>
<span class="line"><span>FROM   ((SELECT *</span></span>
<span class="line"><span>         FROM   my_order o </span></span>
<span class="line"><span>                INNER JOIN my_appraise a </span></span>
<span class="line"><span>                        ON a.orderid = o.id </span></span>
<span class="line"><span>                           AND is_reply = 0 </span></span>
<span class="line"><span>         ORDER  BY appraise_time DESC </span></span>
<span class="line"><span>         LIMIT  0, 20) </span></span>
<span class="line"><span>        UNION ALL </span></span>
<span class="line"><span>        (SELECT *</span></span>
<span class="line"><span>         FROM   my_order o </span></span>
<span class="line"><span>                INNER JOIN my_appraise a </span></span>
<span class="line"><span>                        ON a.orderid = o.id </span></span>
<span class="line"><span>                           AND is_reply = 1 </span></span>
<span class="line"><span>         ORDER  BY appraise_time DESC </span></span>
<span class="line"><span>         LIMIT  0, 20)) t </span></span>
<span class="line"><span>ORDER  BY  is_reply ASC, </span></span>
<span class="line"><span>          appraisetime DESC </span></span>
<span class="line"><span>LIMIT  20;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><h3 id="_5-exists语句" tabindex="-1">5. EXISTS语句 <a class="header-anchor" href="#_5-exists语句" aria-label="Permalink to &quot;5. EXISTS语句&quot;">​</a></h3><p>MySQL对待EXISTS子句时，仍然采用嵌套子查询的执行方式。如下面的SQL语句：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>SELECT *</span></span>
<span class="line"><span>FROM   my_neighbor n </span></span>
<span class="line"><span>       LEFT JOIN my_neighbor_apply sra </span></span>
<span class="line"><span>              ON n.id = sra.neighbor_id </span></span>
<span class="line"><span>                 AND sra.user_id = &#39;xxx&#39; </span></span>
<span class="line"><span>WHERE  n.topic_status &lt; 4 </span></span>
<span class="line"><span>       AND EXISTS(SELECT 1 </span></span>
<span class="line"><span>                  FROM   message_info m </span></span>
<span class="line"><span>                  WHERE  n.id = m.neighbor_id </span></span>
<span class="line"><span>                         AND m.inuser = &#39;xxx&#39;) </span></span>
<span class="line"><span>       AND n.topic_type &lt;&gt; 5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>执行计划为：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>+----+--------------------+-------+------+-----+------------------------------------------+---------+-------+---------+ -----+</span></span>
<span class="line"><span>| id | select_type        | table | type | possible_keys     | key   | key_len | ref   | rows    | Extra   |</span></span>
<span class="line"><span>+----+--------------------+-------+------+ -----+------------------------------------------+---------+-------+---------+ -----+</span></span>
<span class="line"><span>|  1 | PRIMARY            | n     | ALL  |  | NULL     | NULL    | NULL  | 1086041 | Using where                   |</span></span>
<span class="line"><span>|  1 | PRIMARY            | sra   | ref  |  | idx_user_id | 123     | const |       1 | Using where          |</span></span>
<span class="line"><span>|  2 | DEPENDENT SUBQUERY | m     | ref  |  | idx_message_info   | 122     | const |       1 | Using index condition; Using where |</span></span>
<span class="line"><span>+----+--------------------+-------+------+ -----+------------------------------------------+---------+-------+---------+ -----+</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>去掉exists更改为join，能够避免嵌套子查询，将执行时间从1.93秒降低为1毫秒。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>SELECT *</span></span>
<span class="line"><span>FROM   my_neighbor n </span></span>
<span class="line"><span>       INNER JOIN message_info m </span></span>
<span class="line"><span>               ON n.id = m.neighbor_id </span></span>
<span class="line"><span>                  AND m.inuser = &#39;xxx&#39; </span></span>
<span class="line"><span>       LEFT JOIN my_neighbor_apply sra </span></span>
<span class="line"><span>              ON n.id = sra.neighbor_id </span></span>
<span class="line"><span>                 AND sra.user_id = &#39;xxx&#39; </span></span>
<span class="line"><span>WHERE  n.topic_status &lt; 4 </span></span>
<span class="line"><span>       AND n.topic_type &lt;&gt; 5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>新的执行计划：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>+----+-------------+-------+--------+ -----+------------------------------------------+---------+ -----+------+ -----+</span></span>
<span class="line"><span>| id | select_type | table | type   | possible_keys     | key       | key_len | ref   | rows | Extra                 |</span></span>
<span class="line"><span>+----+-------------+-------+--------+ -----+------------------------------------------+---------+ -----+------+ -----+</span></span>
<span class="line"><span>|  1 | SIMPLE      | m     | ref    | | idx_message_info   | 122     | const    |    1 | Using index condition |</span></span>
<span class="line"><span>|  1 | SIMPLE      | n     | eq_ref | | PRIMARY   | 122     | ighbor_id |    1 | Using where      |</span></span>
<span class="line"><span>|  1 | SIMPLE      | sra   | ref    | | idx_user_id | 123     | const     |    1 | Using where           |</span></span>
<span class="line"><span>+----+-------------+-------+--------+ -----+------------------------------------------+---------+ -----+------+ -----+</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="_6-条件下推" tabindex="-1">6. 条件下推 <a class="header-anchor" href="#_6-条件下推" aria-label="Permalink to &quot;6. 条件下推&quot;">​</a></h3><p>外部查询条件不能够下推到复杂的视图或子查询的情况有：</p><ol><li>聚合子查询；</li><li>含有LIMIT的子查询；</li><li>UNION 或UNION ALL子查询；</li><li>输出字段中的子查询；</li></ol><p>如下面的语句，从执行计划可以看出其条件作用于聚合子查询之后：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>SELECT * </span></span>
<span class="line"><span>FROM   (SELECT target, </span></span>
<span class="line"><span>               Count(*) </span></span>
<span class="line"><span>        FROM   operation </span></span>
<span class="line"><span>        GROUP  BY target) t </span></span>
<span class="line"><span>WHERE  target = &#39;rm-xxxx&#39; </span></span>
<span class="line"><span>+----+-------------+------------+-------+---------------+-------------+---------+-------+------+-------------+</span></span>
<span class="line"><span>| id | select_type | table      | type  | possible_keys | key         | key_len | ref   | rows | Extra       |</span></span>
<span class="line"><span>+----+-------------+------------+-------+---------------+-------------+---------+-------+------+-------------+</span></span>
<span class="line"><span>|  1 | PRIMARY     | &lt;derived2&gt; | ref   | &lt;auto_key0&gt;   | &lt;auto_key0&gt; | 514     | const |    2 | Using where |</span></span>
<span class="line"><span>|  2 | DERIVED     | operation  | index | idx_4         | idx_4       | 519     | NULL  |   20 | Using index |</span></span>
<span class="line"><span>+----+-------------+------------+-------+---------------+-------------+---------+-------+------+-------------+</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>确定从语义上查询条件可以直接下推后，重写如下：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>SELECT target, </span></span>
<span class="line"><span>       Count(*) </span></span>
<span class="line"><span>FROM   operation </span></span>
<span class="line"><span>WHERE  target = &#39;rm-xxxx&#39; </span></span>
<span class="line"><span>GROUP  BY target</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>执行计划变为：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>+----+-------------+-----------+------+---------------+-------+---------+-------+------+--------------------+</span></span>
<span class="line"><span>| id | select_type | table | type | possible_keys | key | key_len | ref | rows | Extra |</span></span>
<span class="line"><span>+----+-------------+-----------+------+---------------+-------+---------+-------+------+--------------------+</span></span>
<span class="line"><span>| 1 | SIMPLE | operation | ref | idx_4 | idx_4 | 514 | const | 1 | Using where; Using index |</span></span>
<span class="line"><span>+----+-------------+-----------+------+---------------+-------+---------+-------+------+--------------------+</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>关于MySQL外部条件不能下推的详细解释说明请参考以前文章：<a href="http://mysql.taobao.org/monthly/2016/07/08/" target="_blank" rel="noreferrer">MySQL · 性能优化 · 条件下推到物化表</a></p><h3 id="_7-提前缩小范围" tabindex="-1">7. 提前缩小范围 <a class="header-anchor" href="#_7-提前缩小范围" aria-label="Permalink to &quot;7. 提前缩小范围&quot;">​</a></h3><p>先上初始SQL语句：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>SELECT * </span></span>
<span class="line"><span>FROM   my_order o </span></span>
<span class="line"><span>       LEFT JOIN my_userinfo u </span></span>
<span class="line"><span>              ON o.uid = u.uid</span></span>
<span class="line"><span>       LEFT JOIN my_productinfo p </span></span>
<span class="line"><span>              ON o.pid = p.pid </span></span>
<span class="line"><span>WHERE  ( o.display = 0 ) </span></span>
<span class="line"><span>       AND ( o.ostaus = 1 ) </span></span>
<span class="line"><span>ORDER  BY o.selltime DESC </span></span>
<span class="line"><span>LIMIT  0, 15</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>该SQL语句原意是：先做一系列的左连接，然后排序取前15条记录。从执行计划也可以看出，最后一步估算排序记录数为90万，时间消耗为12秒。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>+----+-------------+-------+--------+---------------+---------+---------+-----------------+--------+----------------------------------------------------+</span></span>
<span class="line"><span>| id | select_type | table | type   | possible_keys | key     | key_len | ref             | rows   | Extra                                              |</span></span>
<span class="line"><span>+----+-------------+-------+--------+---------------+---------+---------+-----------------+--------+----------------------------------------------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | o     | ALL    | NULL          | NULL    | NULL    | NULL            | 909119 | Using where; Using temporary; Using filesort       |</span></span>
<span class="line"><span>|  1 | SIMPLE      | u     | eq_ref | PRIMARY       | PRIMARY | 4       | o.uid |      1 | NULL                                               |</span></span>
<span class="line"><span>|  1 | SIMPLE      | p     | ALL    | PRIMARY       | NULL    | NULL    | NULL            |      6 | Using where; Using join buffer (Block Nested Loop) |</span></span>
<span class="line"><span>+----+-------------+-------+--------+---------------+---------+---------+-----------------+--------+----------------------------------------------------+</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>由于最后WHERE条件以及排序均针对最左主表，因此可以先对my_order排序提前缩小数据量再做左连接。SQL重写后如下，执行时间缩小为1毫秒左右。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>SELECT * </span></span>
<span class="line"><span>FROM (</span></span>
<span class="line"><span>SELECT * </span></span>
<span class="line"><span>FROM   my_order o </span></span>
<span class="line"><span>WHERE  ( o.display = 0 ) </span></span>
<span class="line"><span>       AND ( o.ostaus = 1 ) </span></span>
<span class="line"><span>ORDER  BY o.selltime DESC </span></span>
<span class="line"><span>LIMIT  0, 15</span></span>
<span class="line"><span>) o </span></span>
<span class="line"><span>     LEFT JOIN my_userinfo u </span></span>
<span class="line"><span>              ON o.uid = u.uid </span></span>
<span class="line"><span>     LEFT JOIN my_productinfo p </span></span>
<span class="line"><span>              ON o.pid = p.pid </span></span>
<span class="line"><span>ORDER BY  o.selltime DESC</span></span>
<span class="line"><span>limit 0, 15</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><p>再检查执行计划：子查询物化后（select_type=DERIVED)参与JOIN。虽然估算行扫描仍然为90万，但是利用了索引以及LIMIT 子句后，实际执行时间变得很小。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>+----+-------------+------------+--------+---------------+---------+---------+-------+--------+----------------------------------------------------+</span></span>
<span class="line"><span>| id | select_type | table      | type   | possible_keys | key     | key_len | ref   | rows   | Extra                                              |</span></span>
<span class="line"><span>+----+-------------+------------+--------+---------------+---------+---------+-------+--------+----------------------------------------------------+</span></span>
<span class="line"><span>|  1 | PRIMARY     | &lt;derived2&gt; | ALL    | NULL          | NULL    | NULL    | NULL  |     15 | Using temporary; Using filesort                    |</span></span>
<span class="line"><span>|  1 | PRIMARY     | u          | eq_ref | PRIMARY       | PRIMARY | 4       | o.uid |      1 | NULL                                               |</span></span>
<span class="line"><span>|  1 | PRIMARY     | p          | ALL    | PRIMARY       | NULL    | NULL    | NULL  |      6 | Using where; Using join buffer (Block Nested Loop) |</span></span>
<span class="line"><span>|  2 | DERIVED     | o          | index  | NULL          | idx_1   | 5       | NULL  | 909112 | Using where                                        |</span></span>
<span class="line"><span>+----+-------------+------------+--------+---------------+---------+---------+-------+--------+----------------------------------------------------+</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="_8-中间结果集下推" tabindex="-1">8. 中间结果集下推 <a class="header-anchor" href="#_8-中间结果集下推" aria-label="Permalink to &quot;8. 中间结果集下推&quot;">​</a></h3><p>再来看下面这个已经初步优化过的例子(左连接中的主表优先作用查询条件)：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>SELECT    a.*, </span></span>
<span class="line"><span>          c.allocated </span></span>
<span class="line"><span>FROM      ( </span></span>
<span class="line"><span>              SELECT   resourceid </span></span>
<span class="line"><span>              FROM     my_distribute d </span></span>
<span class="line"><span>                   WHERE    isdelete = 0 </span></span>
<span class="line"><span>                   AND      cusmanagercode = &#39;1234567&#39; </span></span>
<span class="line"><span>                   ORDER BY salecode limit 20) a </span></span>
<span class="line"><span>LEFT JOIN </span></span>
<span class="line"><span>          ( </span></span>
<span class="line"><span>              SELECT   resourcesid， sum(ifnull(allocation, 0) * 12345) allocated </span></span>
<span class="line"><span>              FROM     my_resources </span></span>
<span class="line"><span>                   GROUP BY resourcesid) c </span></span>
<span class="line"><span>ON        a.resourceid = c.resourcesid</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p>那么该语句还存在其它问题吗？不难看出子查询 c 是全表聚合查询，在表数量特别大的情况下会导致整个语句的性能下降。</p><p>其实对于子查询 c，左连接最后结果集只关心能和主表resourceid能匹配的数据。因此我们可以重写语句如下，执行时间从原来的2秒下降到2毫秒。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>SELECT    a.*, </span></span>
<span class="line"><span>          c.allocated </span></span>
<span class="line"><span>FROM      ( </span></span>
<span class="line"><span>                   SELECT   resourceid </span></span>
<span class="line"><span>                   FROM     my_distribute d </span></span>
<span class="line"><span>                   WHERE    isdelete = 0 </span></span>
<span class="line"><span>                   AND      cusmanagercode = &#39;1234567&#39; </span></span>
<span class="line"><span>                   ORDER BY salecode limit 20) a </span></span>
<span class="line"><span>LEFT JOIN </span></span>
<span class="line"><span>          ( </span></span>
<span class="line"><span>                   SELECT   resourcesid， sum(ifnull(allocation, 0) * 12345) allocated </span></span>
<span class="line"><span>                   FROM     my_resources r, </span></span>
<span class="line"><span>                            ( </span></span>
<span class="line"><span>                                     SELECT   resourceid </span></span>
<span class="line"><span>                                     FROM     my_distribute d </span></span>
<span class="line"><span>                                     WHERE    isdelete = 0 </span></span>
<span class="line"><span>                                     AND      cusmanagercode = &#39;1234567&#39; </span></span>
<span class="line"><span>                                     ORDER BY salecode limit 20) a </span></span>
<span class="line"><span>                   WHERE    r.resourcesid = a.resourcesid </span></span>
<span class="line"><span>                   GROUP BY resourcesid) c </span></span>
<span class="line"><span>ON        a.resourceid = c.resourcesid</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><p>但是子查询 a 在我们的SQL语句中出现了多次。这种写法不仅存在额外的开销，还使得整个语句显的繁杂。使用WITH语句再次重写：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>WITH a AS </span></span>
<span class="line"><span>( </span></span>
<span class="line"><span>         SELECT   resourceid </span></span>
<span class="line"><span>         FROM     my_distribute d </span></span>
<span class="line"><span>         WHERE    isdelete = 0 </span></span>
<span class="line"><span>         AND      cusmanagercode = &#39;1234567&#39; </span></span>
<span class="line"><span>         ORDER BY salecode limit 20)</span></span>
<span class="line"><span>SELECT    a.*, </span></span>
<span class="line"><span>          c.allocated </span></span>
<span class="line"><span>FROM      a </span></span>
<span class="line"><span>LEFT JOIN </span></span>
<span class="line"><span>          ( </span></span>
<span class="line"><span>                   SELECT   resourcesid， sum(ifnull(allocation, 0) * 12345) allocated </span></span>
<span class="line"><span>                   FROM     my_resources r, </span></span>
<span class="line"><span>                            a </span></span>
<span class="line"><span>                   WHERE    r.resourcesid = a.resourcesid </span></span>
<span class="line"><span>                   GROUP BY resourcesid) c </span></span>
<span class="line"><span>ON        a.resourceid = c.resourcesid</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><p>AliSQL即将推出WITH语法，敬请期待。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><ol><li>数据库编译器产生执行计划，决定着SQL的实际执行方式。但是编译器只是尽力服务，所有数据库的编译器都不是尽善尽美的。上述提到的多数场景，在其它数据库中也存在性能问题。了解数据库编译器的特性，才能避规其短处，写出高性能的SQL语句。</li><li>程序员在设计数据模型以及编写SQL语句时，要把算法的思想或意识带进来。</li><li>编写复杂SQL语句要养成使用WITH语句的习惯。简洁且思路清晰的SQL语句也能减小数据库的负担 ^^。</li><li>使用云上数据库遇到难点（不局限于SQL问题），随时寻求阿里云原厂专家服务的帮助。</li></ol>`,71),i=[l];function r(c,b,t,u,d,o){return a(),n("div",null,i)}const g=s(e,[["render",r]]);export{h as __pageData,g as default};
